insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Lying Leg Curl', 'Zakopávání vleže', 'Hamstrings', 'Isolation', 'Machine', 'Curl heels to glutes, squeeze, control back.', 'Zakop paty k hýždím, zatni, kontrolovaně zpět.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Smith Machine Incline Press', 'Tlak na šikmé lavici na Smithově stroji', 'Chest', 'Horizontal Push', 'Smith', 'Bench ~30° in the bar path, bar to upper chest, controlled press.', 'Lavice ~30° v dráze osy, činka k horní části hrudníku, kontrolovaný tlak.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Hip Abduction Machine', 'Roznožování ve stroji (abduktory)', 'Glutes', 'Isolation', 'Machine', 'Slight lean forward, push knees out, squeeze glutes.', 'Mírný předklon, roznož kolena, zatni hýždě.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('EZ-Bar Curl', 'Bicepsový zdvih s EZ osou', 'Biceps', 'Isolation', 'EZ-bar', 'EZ grip, elbows at sides, smooth curl.', 'Úchop na EZ ose, lokty u těla, plynulý zdvih.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Lat Pulldown', 'Stahování horní kladky nadhmatem', 'Lats', 'Vertical Pull', 'Cable', 'Slight lean back, bar to upper chest, elbows down and in.', 'Mírný záklon, hrazdu k horní části hrudníku, lokty dolů a dovnitř.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Lateral Raise', 'Upažování s jednoručkami', 'Side Delts', 'Isolation', 'Dumbbell', 'Soft elbows, lead with elbows, raise to shoulder height.', 'Mírně pokrčené lokty, veď lokty, zvedej do výše ramen.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Glute Bridge', 'Most (zved ání pánve)', 'Glutes', 'Hinge', 'Barbell', 'Back on floor, drive hips up, squeeze glutes at top.', 'Záda na zemi, vytlač boky, zatni hýždě nahoře.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Romanian Deadlift', 'Rumunský mrtvý tah', 'Hamstrings', 'Hinge', 'Barbell', 'Soft knees, push hips back, bar close, feel the hamstrings.', 'Mírně pokrčená kolena, boky vzad, osa u těla, cítit hamstringy.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Hanging Leg Raise', 'Zvedání nohou ve vise', 'Core', 'Core', 'Bodyweight', 'No swing, curl pelvis up, control down.', 'Bez hmitu, podsáď pánev nahoru, kontrolovaně dolů.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Overhead Dumbbell Extension', 'Zapažování s jednoručkou nad hlavou', 'Triceps', 'Isolation', 'Dumbbell', 'Both hands under the bell, lower behind head, extend.', 'Obě ruce pod hlavu činky, spusť za hlavu, propni.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Pull-up', 'Shyby nadhmatem', 'Lats', 'Vertical Pull', 'Bodyweight', 'Full hang, drive elbows down to ribs, chest toward bar.', 'Plný vis, tahni lokty dolů k žebrům, hrudník k hrazdě.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Incline Dumbbell Curl', 'Bicepsový zdvih na šikmé lavici', 'Biceps', 'Isolation', 'Dumbbell', 'Lie back, arms hang, curl with elbows still.', 'Opři se vzad, paže visí, zvedej s lokty na místě.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Concentration Curl', 'Koncentrovaný zdvih', 'Biceps', 'Isolation', 'Dumbbell', 'Elbow on inner thigh, squeeze hard at the top.', 'Loket opřený o stehno, zatni v horní pozici.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Cable Lateral Raise', 'Upažování na kladce (jednoruč)', 'Side Delts', 'Isolation', 'Cable', 'Cable behind body, raise smoothly, constant tension.', 'Kladka za tělem, upažuj plynule, stálé napětí.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Close-Grip Pulldown', 'Stahování horní kladky úzkým úchopem', 'Lats', 'Vertical Pull', 'Cable', 'Neutral close grip, elbows to hips, full stretch up top.', 'Neutrální úzký úchop, lokty k bokům, plné protažení nahoře.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Leg Press', 'Leg press (tlak nohama)', 'Quads', 'Squat', 'Machine', 'Feet mid-platform, lower to ~90°, don''t lock hard.', 'Chodidla na středu plošiny, spusť do ~90°, neprodpínej tvrdě.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Front Raise', 'Předpažování s jednoručkami', 'Front Delts', 'Isolation', 'Dumbbell', 'Raise to shoulder height, no swing, control down.', 'Předpažuj do výše ramen, bez hmitu, kontrolovaně dolů.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Dumbbell Curl', 'Bicepsový zdvih s jednoručkami', 'Biceps', 'Isolation', 'Dumbbell', 'Alternate arms, supinate wrist at the top.', 'Střídej paže, nahoře vytoč zápěstí (supinace).');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Cable Crunch', 'Zkracovačky na kladce', 'Core', 'Core', 'Cable', 'Round spine down, crunch with abs not arms.', 'Zakulať páteř dolů, krč břichem, ne pažemi.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Cable Curl', 'Bicepsový zdvih na spodní kladce', 'Biceps', 'Isolation', 'Cable', 'Constant tension, elbows pinned, control down.', 'Stálé napětí, lokty u těla, kontrolovaně dolů.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Overhead Cable Extension', 'Zapažování na kladce nad hlavou', 'Triceps', 'Isolation', 'Cable', 'Elbows high, extend overhead, feel the stretch.', 'Lokty vysoko, propni nad hlavou, cítit protažení.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Copenhagen Plank', 'Kodaňské prkno (adduktory)', 'Adductors', 'Core', 'Bodyweight', 'Top leg on bench, hold hips up, brace inner thigh.', 'Horní noha na lavici, drž pánev nahoře, zpevni vnitřní stehno.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Farmer''s Carry', 'Farmářská chůze', 'Forearms', 'Carry', 'Dumbbell', 'Heavy, tall posture, firm grip, walk controlled.', 'Těžké činky, vzpřímený postoj, pevný úchop, kontrolovaná chůze.');
