insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('One-Arm Dumbbell Row', 'Veslování s jednoručkou (jednoruč)', 'Upper Back', 'Horizontal Pull', 'Dumbbell', 'Support on bench, pull dumbbell to hip, control down.', 'Opora o lavici, tahni jednoručku k boku, kontrolovaně dolů.');
