insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Skull Crusher', 'Francouzský tlak vleže (skull crusher)', 'Triceps', 'Isolation', 'EZ-bar', 'Lower to forehead, elbows still, extend up.', 'Spusť k čelu, lokty na místě, propni nahoru.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Plank', 'Prkno (plank)', 'Core', 'Core', 'Bodyweight', 'Straight line, brace abs, don''t let hips sag.', 'Rovná přímka, zpevni břicho, nepropínej se v bocích.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Push-up', 'Kliky', 'Chest', 'Horizontal Push', 'Bodyweight', 'Body in a straight line, elbows ~45°, full range, brace the core.', 'Tělo v jedné přímce, lokty cca 45°, plný rozsah, zpevni střed těla.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Low-to-High Cable Fly', 'Rozpažování na spodních kladkách (zdola nahoru)', 'Chest', 'Isolation', 'Cable', 'Pulleys low, sweep up and in to nose height, squeeze upper chest.', 'Kladky dole, veď nahoru a dovnitř do výše nosu, zatni horní část prsou.');
