insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Decline Sit-up', 'Sed-lehy na záporné lavici', 'Core', 'Core', 'Bodyweight', 'Controlled sit-up, roll the spine, no bouncing.', 'Kontrolovaný sed-leh, bedra plynule, nezhoupavej.');
