insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Seated Leg Curl', 'Zakopávání vsedě', 'Hamstrings', 'Isolation', 'Machine', 'Pull heels under seat, squeeze, slow return.', 'Stáhni paty pod sedák, zatni, pomalý návrat.');
