insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Inverted Row', 'Australské shyby (veslování ve vise)', 'Upper Back', 'Horizontal Pull', 'Bodyweight', 'Body rigid, pull chest to bar, squeeze blades.', 'Tělo zpevněné, tahni hrudník k tyči, stáhni lopatky.');
