insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Barbell Curl', 'Bicepsový zdvih s velkou činkou', 'Biceps', 'Isolation', 'Barbell', 'Elbows pinned, curl without swing, squeeze at top.', 'Lokty u těla, zvedej bez hmitu, nahoře zatni.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Nordic Curl', 'Nordické zakopávání', 'Hamstrings', 'Isolation', 'Bodyweight', 'Ankles anchored, lower slowly forward, brake with hamstrings.', 'Kotníky fixní, klesej pomalu vpřed, brzdi hamstringy.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Machine Lateral Raise', 'Upažování ve stroji', 'Side Delts', 'Isolation', 'Machine', 'Elbows against pads, raise to shoulder height, slow down.', 'Lokty proti opěrkám, zvedej do výše ramen, pomalu dolů.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Reverse Curl', 'Bicepsový zdvih nadhmatem', 'Forearms', 'Isolation', 'EZ-bar', 'Overhand grip, elbows at sides, curl without swing.', 'Nadhmat, lokty u těla, zvedej bez hmitu.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Hip Thrust', 'Hip thrust (zved ání pánve s činkou)', 'Glutes', 'Hinge', 'Barbell', 'Upper back on bench, chin tucked, drive hips up, squeeze glutes.', 'Horní záda o lavici, brada zasunutá, vytlač boky vzhůru, zatni hýždi.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Machine Chest Press', 'Tlak na prsa ve stroji', 'Chest', 'Horizontal Push', 'Machine', 'Handles at mid-chest, press without harsh lockout, control the return.', 'Madla ve výši středu hrudníku, tlač bez tvrdého propnutí, kontroluj návrat.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Seated Calf Raise', 'Výpony vsedě', 'Calves', 'Isolation', 'Machine', 'Knees fixed, full range, slow down.', 'Kolena fixní, plný rozsah, pomalu dolů.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Stiff-Leg Deadlift', 'Mrtvý tah s napjatýma nohama', 'Hamstrings', 'Hinge', 'Barbell', 'Near-straight knees, hips back, lower to a stretch.', 'Téměř napjatá kolena, boky vzad, spusť do protažení.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Rack Pull', 'Mrtvý tah z podstavců (rack pull)', 'Upper Back', 'Hinge', 'Barbell', 'Bar just below knees, brace, pull and lock hips.', 'Osa těsně pod kolena, zpevni střed, táhni a propni boky.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Chest-Supported Row', 'Veslování s oporou hrudníku', 'Upper Back', 'Horizontal Pull', 'Machine', 'Chest on pad, row to ribs, pause and squeeze.', 'Hrudník o opěrku, tahni k žebrům, pauza a zatni.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Frog Pump', 'Žabí zved ání pánve', 'Glutes', 'Isolation', 'Bodyweight', 'Soles together, knees out, drive hips up and squeeze.', 'Chodidla k sobě, kolena ven, vytlač boky a zatni.');
insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Hip Adduction Machine', 'Stahování ve stroji (adduktory)', 'Adductors', 'Isolation', 'Machine', 'Draw knees together, squeeze, control back.', 'Stáhni kolena k sobě, zatni, kontrolovaně zpět.');
