insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('T-Bar Row', 'T-bar veslování', 'Upper Back', 'Horizontal Pull', 'Barbell', 'Hinge, pull handles to chest, drive elbows back.', 'Předklon, tahni madla k hrudníku, lokty vzad.');
