insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Barbell Shrug', 'Krčení ramen s velkou činkou', 'Traps', 'Isolation', 'Barbell', 'Shrug straight up, pause at top, control down.', 'Krč ramena přímo vzhůru, pauza nahoře, kontrolovaně dolů.');
