insert into exercises (name_en, name_cz, primary_muscle, movement, equipment, cue_en, cue_cz) values ('Smith Machine Squat', 'Dřep na Smithově stroji', 'Quads', 'Squat', 'Smith', 'Feet slightly forward, flat back, controlled squat.', 'Chodidla mírně vpřed, záda rovná, kontrolovaný dřep.');
