-- =====================================================================
--  IRON DOCTRINE — Phase 1, file #3: DATA MIGRATION (from Notion)
--  Run in: Supabase Dashboard -> SQL Editor -> New query -> Run
--  Run AFTER 001_schema.sql and 002_rls.sql.
--
--  Linking strategy: child rows resolve their parent by NATURAL KEY via
--  subquery (coaches.email, clients.notion_id, exercises.name_en), so we
--  never hand-manage UUIDs. Service role runs this, bypassing RLS.
--
--  NOTE: all clients are TEST data -> tagged is_test = true. Purge later
--  with:  delete from clients where is_test = true;  (cascades children)
-- =====================================================================

-- Tag column for easy test-data purge (idempotent).
alter table clients add column if not exists is_test boolean not null default false;

